import React from 'react';
import { Formik, Form, Field, ErrorMessage } from 'formik'; //for form
import * as Yup from 'yup'; //for validation
import axios from 'axios';
import { useNavigate } from 'react-router-dom';

function AddPost() {

    let navigate = useNavigate();

    const initialValues = {
        title: "",
        postText: "",
        username: "",
    };

    const onSubmit = (data) => {
        axios.post('http://localhost:3001/posts', data).then((response) => {
            // console.log(response, "data added to database");
            navigate('/');
        });
    };

    const validationSchema = Yup.object().shape({
        title: Yup.string().required("You have to have a title!"),
        postText: Yup.string().required(),
        username: Yup.string().min(3).max(16).required(),
    });

  return (
    <div className='addPostPage'>
        <Formik initialValues={initialValues} onSubmit={onSubmit} validationSchema={validationSchema} >
            <Form className='formContainer'>
                <label className='formLabel'>Title:</label>
                <ErrorMessage name='title' component="span" />
                <Field 
                    id="inputCreateTitle" 
                    name="title" 
                    placeholder="Enter your title" 
                    autoComplete="off"
                />
                <label className='formLabel'>Post:</label>
                <ErrorMessage name='postText' component="span" />
                <Field 
                    id="inputCreatePost" 
                    name="postText" 
                    placeholder="Enter your post" 
                    autoComplete="off" 
                />
                <label className='formLabel'>Name:</label>
                <ErrorMessage name='username' component="span" />
                <Field 
                    id="inputCreateUser" 
                    name="username" 
                    placeholder="Enter your name" 
                    autoComplete="off"
                />
                <button type='submit'>Create a Post</button>
            </Form> 
        </Formik>
    </div>
  )
}

export default AddPost
